eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   chef: () => (/* binding */ chef),\n/* harmony export */   craft: () => (/* binding */ craft),\n/* harmony export */   design: () => (/* binding */ design),\n/* harmony export */   finalCta: () => (/* binding */ finalCta),\n/* harmony export */   footer: () => (/* binding */ footer),\n/* harmony export */   hero: () => (/* binding */ hero),\n/* harmony export */   maker: () => (/* binding */ maker),\n/* harmony export */   nav: () => (/* binding */ nav),\n/* harmony export */   sections: () => (/* binding */ sections),\n/* harmony export */   video: () => (/* binding */ video)\n/* harmony export */ });\n/**\n * ============================================================================\n *  ANRI · \"Sai Oua\" Campaign — SINGLE SOURCE OF TRUTH\n * ============================================================================\n *  Edit ALL copy and image paths here. Both the Pass-1 wireframe and the\n *  Pass-2 high-fidelity page read from this file, so you never touch JSX\n *  to update text or swap a photo.\n *\n *  COPY RULE: Thai is verbatim from story-website-landing-page.png. Do not\n *  auto-correct Thai spelling. The English headline keeps the reference's\n *  spelling \"Untranslateble\" intentionally.\n *\n *  IMAGE RULE: every visual is a `src` variable below. Drop a real file into\n *  /public/images with the same name (or point the variable elsewhere) and it\n *  appears everywhere. Until then a labeled placeholder block renders — never\n *  a broken <img>.\n *\n *  VIDEO RULE: see `video.src` — set it to an .mp4 path OR a YouTube/Vimeo\n *  embed URL and the player swaps in. Leave it null to keep the poster +\n *  play-button placeholder.\n * ============================================================================\n */ const img = (src, alt, placeholder)=>({\n        src,\n        alt,\n        placeholder\n    });\n/* ── Navigation ──────────────────────────────────────────────────────────── */ const nav = {\n    brand: \"Anri\",\n    brandMark: \"アンリ\",\n    links: [\n        {\n            label: \"Anri's Signature\",\n            href: \"https://anribakery.com/#signature\"\n        },\n        {\n            label: \"Menu\",\n            href: \"https://anribakery.com/#menu\"\n        },\n        {\n            label: \"Storing Tips\",\n            href: \"https://anribakery.com/#storing-tips\"\n        },\n        {\n            label: \"Anri's Story\",\n            href: \"https://anribakery.com/#story\"\n        },\n        {\n            label: \"Our Shops\",\n            href: \"https://anribakery.com/#shops\"\n        },\n        {\n            label: \"Delivery\",\n            href: \"https://anribakery.com/#delivery\"\n        },\n        {\n            label: \"Member\",\n            href: \"https://anribakery.com/member/\"\n        },\n        {\n            label: \"Contact\",\n            href: \"https://anribakery.com/#contact\"\n        }\n    ]\n};\n/* ── Hero ────────────────────────────────────────────────────────────────── */ const hero = {\n    headline: \"The Untranslateble Taste\",\n    thaiSubhead: \"รสชาติที่อธิบายไม่ได้\",\n    eyebrow: \"\",\n    paragraph: \"100 ปีที่ผ่านมา Anri ได้แปลความเป็นญี่ปุ่น ผ่านแบบ Aomori Apple Pie และอื่นๆ ให้คนไทยมาโดยตลอด ในวินาทีนี้ถึงเวลาแล้ว ที่ Anri จะเสาะหาของดีของไทย เพื่อแปลออกมาเป็นภาษาของ Anri บ้าง\",\n    cta: \"PREORDER NOW\",\n    product: img(null, \"Signature Anri Sai Oua pastry — woven lattice crust revealing herb sausage filling, beside its ANRI gift box\", \"IMAGE: signature woven-lattice sai-oua pastry on a stone plate, ANRI box behind, soft mountain backdrop — hero, right side\"),\n    background: img(null, \"Misty Chiang Mai mountains at dawn\", \"BG: soft misty northern-Thailand mountains, warm dawn light, low contrast\"),\n    productBoxLabel: \"ANRI\",\n    productBoxSub: \"THE UNTRANSLATEBLE TASTE\"\n};\n/* ── Video section (immediately after hero) ────────────────────────────────\n *  ► TO ADD THE REAL VIDEO: set `video.src` below.\n *      • Self-hosted file:  \"/videos/anri-sai-oua.mp4\"  (kind: \"file\")\n *      • YouTube / Vimeo:   \"https://www.youtube.com/embed/XXXX\" (kind: \"embed\")\n *  Leave src: null to keep the poster + play-button placeholder.\n * ------------------------------------------------------------------------- */ const video = {\n    src: \"/videos/Anri_OurStoryToThailand.mp4\",\n    kind: \"file\",\n    poster: img(null, \"Sai oua slowly grilling over charcoal, smoke rising\", \"POSTER: cinematic close-up of sai oua coiled on a charcoal grill, smoke, warm embers\"),\n    caption: \"เรื่องราวที่อธิบายไม่ได้\",\n    captionEn: \"A taste best understood by tasting\"\n};\n/* ── Chapter 1 — Chef's Journey ────────────────────────────────────────────── */ const chef = {\n    eyebrow: \"1st Chapter\",\n    heading: \"Chef's Journey to Chiang Mai\",\n    thaiSubhead: \"เมนูที่อธิบายไม่ได้จากเชียงใหม่\",\n    body: 'เมนูแห่งความบังเอิญ ที่เชฟได้รับการแนะนำให้ลองชิมจากเจ้าของที่พัก จนได้มาเจอ \"ไส้อั่วคำแปง\" รสชาติอันเป็นเอกลักษณ์ ที่แม้แต่เชฟชาวญี่ปุ่นก็ไม่สามารถอธิบายออกมาได้',\n    image: img(null, \"A figure standing before northern Thai mountains and a Lanna temple at golden hour\", \"IMAGE: lone figure facing Chiang Mai mountains / Lanna temple silhouette, golden hour, back to camera\")\n};\n/* ── Chapter 2 — The Maker ─────────────────────────────────────────────────── */ const maker = {\n    heading: \"The Maker\",\n    thaiName: \"คำแปง\",\n    body: \"ไส้อั่วที่อยู่ในครัวซองชิ้นนี้ ถูกสรรค์สร้างขึ้นโดยครอบครัวของคุณแม่คำแปง ผู้ทำไส้อั่วพื้นบ้านจากจังหวัดเชียงใหม่ ที่เครื่องแกงทำเอง เนื้อหมูแน่นมันน้อย ที่มอบความอร่อยจากรสมือคนพื้นที่แท้ๆ\",\n    image: img(null, \"Mae Kham Paeng hand-making sai oua in a rustic northern Thai kitchen, herbs and ingredients around her\", \"IMAGE: maker (Mae Kham Paeng) at work in a warm rustic kitchen, hands shaping sausage, bowls of curry paste & herbs\")\n};\n/* ── Chapter 3 — The Craft ─────────────────────────────────────────────────── */ const craft = {\n    heading: \"The Craft\",\n    thaiName: \"ไส้อั่ว\",\n    body: \"ไส้อั่วที่ผลิตด้วยมือในจำนวนจำกัดต่อวัน ทุกๆ เส้นจะต้องผ่านการปรุง ย่าง และพักอย่างเหมาะสม อีกทั้งยังคงค่อยๆ ย่างบนเตาด้วยมือเหมือนที่คุณแม่คำแปงทำมาตลอด\",\n    image: img(null, \"Coiled sai oua grilling over glowing charcoal with fragrant smoke\", \"IMAGE: sai oua coil over charcoal, smoke and embers, top-down or close 3/4, warm glow\")\n};\n/* ── Chapter 4 — The Design ────────────────────────────────────────────────── */ const design = {\n    heading: \"The Design\",\n    thaiName: \"โคมลายสานล้านนา\",\n    body: \"อีกหนึ่งเอกลักษณ์ของภาคเหนือที่สร้างแรงบันดาลใจให้เชฟของ Anri งานหัตถกรรมพื้นบ้านล้านนาที่ประดับประดาอยู่ทั่วเมือง ถูกนำมาสร้างเป็นแป้งครัวซองที่พันรอบไส้อั่ว เกิดเป็นลายสานเหมือนโคมไม้ไผ่ที่หุ้มของดีจากภาคเหนือไว้ภายใน รอที่จะส่งมอบรสชาติแสนอร่อยที่แม้แต่เชฟก็ไม่สามารถอธิบายได้\",\n    image: img(null, \"Woven bamboo Lanna lantern next to the lattice-wrapped sai oua pastry on banana leaf\", \"IMAGE: woven bamboo Lanna lantern + banana-leaf / lattice packaging detail, warm low-key light\")\n};\n/* ── Final CTA ─────────────────────────────────────────────────────────────── */ const finalCta = {\n    leadIn: \"และคุณคือกลุ่มแรกที่ได้ลิ้มลองรสที่\",\n    bigStatement: \"ไม่สามารถอธิบายได้นี้\",\n    label: \"Early Access Batch\",\n    button: \"PREORDER NOW\",\n    /* Destination for the preorder CTA — also the URL encoded in the desktop QR.\n     Swap for the real order/LINE link when it's ready. */ preorderUrl: \"https://anri.co.th/preorder\",\n    // qrCaption: \"สแกนเพื่อพรีออเดอร์ด้วยมือถือ\",\n    background: img(null, \"Atmospheric northern-Thailand landscape with autumnal red leaves at dusk\", \"BG (full-bleed): moody Chiang Mai dusk, red maple-leaf accents, deep warm shadows\")\n};\n/* ── Footer ────────────────────────────────────────────────────────────────── */ const footer = {\n    brand: \"Anri\",\n    brandMark: \"アンリ\",\n    tagline: \"The Untranslateble Taste — Sai Oua Early Access Batch\",\n    columns: [\n        {\n            title: \"Explore\",\n            links: [\n                \"ANRI'S SIGNATURE\",\n                \"MENU\",\n                \"PROMOTION\",\n                \"ANRI'S STORY\"\n            ]\n        },\n        {\n            title: \"Visit\",\n            links: [\n                \"OUR SHOPS\",\n                \"DELIVERY\",\n                \"MEMBER\",\n                \"CONTACT\"\n            ]\n        }\n    ],\n    social: [\n        \"Instagram\",\n        \"Facebook\",\n        \"LINE\",\n        \"TikTok\"\n    ],\n    contact: {\n        email: \"hello@anri.co.th\",\n        phone: \"+66 2 000 0000\"\n    },\n    copyright: \"\\xa9 2026 Anri Bakery. All rights reserved.\"\n};\n/* ── Section registry (drives nav anchors + ordering) ──────────────────────── */ const sections = [\n    {\n        id: \"hero\",\n        label: \"STORY\"\n    },\n    {\n        id: \"video\",\n        label: \"FILM\"\n    },\n    {\n        id: \"chef\",\n        label: \"THE JOURNEY\"\n    },\n    {\n        id: \"maker\",\n        label: \"THE MAKER\"\n    },\n    {\n        id: \"craft\",\n        label: \"THE CRAFT\"\n    },\n    {\n        id: \"design\",\n        label: \"THE DESIGN\"\n    },\n    {\n        id: \"preorder\",\n        label: \"PREORDER\"\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/content.ts\n");

